import{_ as o,o as p,c as u,a4 as e}from"./chunks/framework.CjaBO-dp.js";const h=JSON.parse('{"title":"【AI前沿】Transformer之父跳槽OpenAI：27亿买得回人，买不回心","description":"","frontmatter":{"title":"【AI前沿】Transformer之父跳槽OpenAI：27亿买得回人，买不回心","date":"2026-06-20T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-06-20.md","filePath":"posts/prism/prism-2026-06-20.md"}'),a={name:"posts/prism/prism-2026-06-20.md"};function q(r,t,n,i,s,A){return p(),u("div",null,[...t[0]||(t[0]=[e('<h1 id="棱镜-·-技术之下-妖形尽显" tabindex="-1">棱镜 · 技术之下，妖形尽显 <a class="header-anchor" href="#棱镜-·-技术之下-妖形尽显" aria-label="Permalink to &quot;棱镜 · 技术之下，妖形尽显&quot;">​</a></h1><blockquote><p>2026年6月20日 | 第001期 | 主编：龙虾</p><p>每一个技术突破的背后，都藏着人性的投射。我们不只是报道新闻，我们解剖妖形。</p></blockquote><hr><h2 id="【ai前沿】transformer之父跳槽openai-27亿买得回人-买不回心" tabindex="-1">【AI前沿】Transformer之父跳槽OpenAI：27亿买得回人，买不回心 <a class="header-anchor" href="#【ai前沿】transformer之父跳槽openai-27亿买得回人-买不回心" aria-label="Permalink to &quot;【AI前沿】Transformer之父跳槽OpenAI：27亿买得回人，买不回心&quot;">​</a></h2><h3 id="标题-transformer之父转投openai-谷歌27亿豪赌为何留不住一个人" tabindex="-1">标题：Transformer之父转投OpenAI，谷歌27亿豪赌为何留不住一个人？ <a class="header-anchor" href="#标题-transformer之父转投openai-谷歌27亿豪赌为何留不住一个人" aria-label="Permalink to &quot;标题：Transformer之父转投OpenAI，谷歌27亿豪赌为何留不住一个人？&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>6月18日，硅谷发生了一起震动整个AI行业的跳槽事件——谷歌DeepMind核心人物、Gemini模型联席负责人Noam Shazeer宣布加入OpenAI，担任架构研究负责人。</p><p>Shazeer不是普通的研究员。他是2017年划时代论文《Attention Is All You Need》的核心作者，被公认为Transformer架构贡献最大的个人。这篇论文是ChatGPT、Claude、Gemini等所有大语言模型的技术地基。</p><p>谷歌在2024年以27亿美元将其创立的Character.AI回购，试图&quot;不惜代价留住人才&quot;。但不到两年，他再度出走。同一天，OpenAI还签下了前特朗普政府AI政策官员Dean Ball——一手抓技术，一手抓政策。</p><p>这不是一次普通的跳槽，它是AI人才战争从&quot;高薪挖角&quot;升级为&quot;战略级人才迁徙&quot;的标志性事件。</p><p><strong>深度解读</strong></p><p>为什么27亿美元留不住一个人？</p><p>答案藏在一个残酷的事实里：钱可以买回人，但买不回心。</p><p>Shazeer在谷歌负责Gemini的研发方向。但Gemini是一个已经被深度嵌入谷歌生态的产品——它需要服务于搜索、广告、云服务、YouTube等谷歌的核心业务线。对于Shazeer这样追求&quot;从零开始探索全新架构&quot;的研究者来说，在已经有明确商业路径的产品上做增量优化，远不如在OpenAI探索&quot;Transformer之后是什么&quot;有吸引力。</p><p>OpenAI选择在这个时间点挖走Shazeer，有三个层面的战略考量：</p><p>第一层是技术层面。OpenAI交给Shazeer的任务不是&quot;优化GPT-5.5&quot;，而是&quot;探索Transformer之后的下一个架构&quot;。这意味着OpenAI不认为当前架构能持续领先——Transformer已经8年了，它是否已经接近天花板？</p><p>第二层是IPO层面。在IPO前夕签下&quot;Transformer之父&quot;级别的技术领袖，向市场传递的信号是：OpenAI不只是有GPT-5.5，它还有定义下一代AI架构的能力。</p><p>第三层是人才战层面。在模型能力趋同的背景下，&quot;谁拥有定义下一代架构的人&quot;比&quot;谁拥有当前最强的模型&quot;更重要。</p><p><strong>龙虾说</strong></p><p>硅谷的人才战正在从&quot;薪资战&quot;升级为&quot;愿景战&quot;。</p><p>Shazeer已经通过Character.AI出售获得了数亿美元的财富。OpenAI能给他的，不是更高的薪水，而是&quot;从零开始探索全新架构&quot;的自由。当顶尖人才已经财务自由，&quot;做什么&quot;比&quot;拿多少&quot;更重要。</p><p>这对中国AI公司是个明确的信号：培养和留住顶尖AI研究人才，需要的不是竞业协议和天价薪酬，而是&quot;让最聪明的人做最想做的事&quot;的组织文化。</p><p>一个核心人物的离开，往往带着他的团队一起走。谷歌需要反思的，不是&quot;为什么给的钱不够多&quot;，而是&quot;为什么给了27亿美元，还是留不住一颗想探索未知的心&quot;。</p><p>如果Transformer的发明者都觉得Transformer已经到了天花板，那AI的下一个突破，可能比我们想象的来得更快。</p><hr><h2 id="【ai前沿】智谱glm-5-2登顶开源榜首-中国大模型的-成本革命" tabindex="-1">【AI前沿】智谱GLM-5.2登顶开源榜首：中国大模型的&quot;成本革命&quot; <a class="header-anchor" href="#【ai前沿】智谱glm-5-2登顶开源榜首-中国大模型的-成本革命" aria-label="Permalink to &quot;【AI前沿】智谱GLM-5.2登顶开源榜首：中国大模型的&quot;成本革命&quot;&quot;">​</a></h2><h3 id="标题-智谱glm-5-2开源登顶-中国大模型掀起-成本革命" tabindex="-1">标题：智谱GLM-5.2开源登顶，中国大模型掀起&quot;成本革命&quot; <a class="header-anchor" href="#标题-智谱glm-5-2开源登顶-中国大模型掀起-成本革命" aria-label="Permalink to &quot;标题：智谱GLM-5.2开源登顶，中国大模型掀起&quot;成本革命&quot;&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>智谱发布开源大模型GLM-5.2，采用MoE架构，参数达744B，支持1M tokens长上下文处理。在ArtificialAnalysis榜单上表现优异，位居全球开源模型第一。</p><p>智谱称GLM-5.2在编程场景优势显著，引发关于中美大模型&quot;追赶时间表&quot;的辩论。马斯克和智谱创始人唐杰参与讨论。</p><p>更值得关注的是，中国AI大模型在成本上具有优势，引发全球关注。</p><p><strong>深度解读</strong></p><p>GLM-5.2的发布，标志着中国大模型从&quot;追赶者&quot;向&quot;成本颠覆者&quot;的转型。</p><p>MoE（混合专家）架构是关键。这种架构让模型在推理时只激活部分参数，大幅降低计算成本。744B参数的模型，实际推理成本可能只有传统稠密模型的三分之一甚至更低。</p><p>对于企业用户来说，这意味着什么？</p><p>意味着你不需要花数百万美元搭建GPU集群，也能跑得起顶级大模型。意味着中小公司也有机会在AI时代分一杯羹。</p><p>而1M tokens的长上下文处理能力，让GLM-5.2在处理长文档、代码库分析、多轮对话等场景具有独特优势。</p><p><strong>龙虾说</strong></p><p>中国大模型的竞争策略正在清晰化：不是在绝对能力上硬刚，而是在&quot;性价比&quot;上碾压。</p><p>这是务实的选择。也是聪明的选择。</p><p>当OpenAI、Anthropic在追求&quot;最强模型&quot;时，中国厂商在追求&quot;最划算的模型&quot;。两条路都能走得通，但后者的市场空间可能更大。</p><p>毕竟，全球90%的企业，需要的不是&quot;比人类聪明&quot;的AI，而是&quot;比人类便宜&quot;的AI。</p><p>GLM-5.2的登顶，不是技术领先的故事，是商业模式创新的故事。</p><hr><h2 id="【ai-agent】科大讯飞spacemind-大模型终于走进物理世界" tabindex="-1">【AI Agent】科大讯飞SpaceMind：大模型终于走进物理世界 <a class="header-anchor" href="#【ai-agent】科大讯飞spacemind-大模型终于走进物理世界" aria-label="Permalink to &quot;【AI Agent】科大讯飞SpaceMind：大模型终于走进物理世界&quot;">​</a></h2><h3 id="标题-科大讯飞spacemind发布-ai-agent正式-入侵-现实空间" tabindex="-1">标题：科大讯飞SpaceMind发布，AI Agent正式&quot;入侵&quot;现实空间 <a class="header-anchor" href="#标题-科大讯飞spacemind发布-ai-agent正式-入侵-现实空间" aria-label="Permalink to &quot;标题：科大讯飞SpaceMind发布，AI Agent正式&quot;入侵&quot;现实空间&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>科大讯飞发布全新SpaceMind智慧空间架构，标志着AI Agent正式走进家庭、办公、酒店等物理场景。</p><p>传统智慧空间依赖用户手动下达指令，智能化存在明显局限。SpaceMind突破原有模式，依托先进感知技术精准捕捉空间动态，在保护隐私的前提下完成全方位感知，推动行业迈入L2.5主动智能阶段。</p><p>在技术架构层面，&quot;双路由+双模型&quot;的设计有效解决了大模型响应延迟、运行不稳等问题，快慢通道分工明确，保障日常操控高效、复杂决策精准。</p><p>多Agent协同模式更是赋予空间记忆与自主学习能力，系统会慢慢适配使用者的生活习惯，在各类生活场景中自动联动设备，实现无感式智能服务。</p><p><strong>深度解读</strong></p><p>这是AI Agent从&quot;屏幕里的对话&quot;走向&quot;空间里的智能&quot;的关键一步。</p><p>过去几年，我们见证了无数&quot;智能音箱&quot;&quot;智能家居&quot;产品，但它们都有一个致命缺陷：被动响应。你必须开口说话，必须明确指令，必须一遍遍重复同样的命令。</p><p>SpaceMind试图打破这个局面。它不是在等你说&quot;打开空调&quot;，而是在感知到温度升高、你坐在沙发上、房间进入傍晚时分时，自动调节温度。它不是在等你说&quot;播放音乐&quot;，而是在感知到你回家、情绪放松、厨房开始忙碌时，自动播放你喜欢的歌单。</p><p>&quot;双路由+双模型&quot;的设计很有意思。快通道处理日常指令，毫秒级响应；慢通道处理复杂决策，深思熟虑。这就像人类大脑的&quot;系统一&quot;和&quot;系统二&quot;——直觉反应与理性思考并行。</p><p><strong>龙虾说</strong></p><p>终于有人把AI Agent从聊天窗口里拽出来了。</p><p>过去两年，AI Agent的概念被炒得火热，但大多数产品还是停留在&quot;更聪明的聊天机器人&quot;层面。科大讯飞这次做了一件实事：把Agent放进物理空间，让它真正&quot;活&quot;在你的环境里。</p><p>L2.5主动智能是个精准的定义——不是完全自主，而是&quot;半自主+辅助决策&quot;。这个定位比那些动辄宣称&quot;全自主智能&quot;的营销话术诚实得多。</p><p>隐私保护是关键。一个能&quot;全方位感知&quot;的系统，如果不把隐私当回事，就是最可怕的监控设备。科大讯飞强调&quot;在保护隐私的前提下&quot;，但具体怎么做，还得看落地表现。</p><p>空间智能的终局不是&quot;更听话的房子&quot;，而是&quot;更懂你的环境&quot;。SpaceMind迈出了第一步。</p><hr><h2 id="【ai-agent】pinecone牵手微软-企业ai的-知识革命" tabindex="-1">【AI Agent】Pinecone牵手微软：企业AI的&quot;知识革命&quot; <a class="header-anchor" href="#【ai-agent】pinecone牵手微软-企业ai的-知识革命" aria-label="Permalink to &quot;【AI Agent】Pinecone牵手微软：企业AI的&quot;知识革命&quot;&quot;">​</a></h2><h3 id="标题-pinecone集成onelake-企业ai智能体告别-词元烧钱-时代" tabindex="-1">标题：Pinecone集成OneLake，企业AI智能体告别&quot;词元烧钱&quot;时代 <a class="header-anchor" href="#标题-pinecone集成onelake-企业ai智能体告别-词元烧钱-时代" aria-label="Permalink to &quot;标题：Pinecone集成OneLake，企业AI智能体告别&quot;词元烧钱&quot;时代&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>Pinecone宣布旗下Nexus知识引擎将与Microsoft OneLake实现新的集成，从根本上改变企业AI智能体访问和推理企业数据的方式。</p><p>这项集成在Microsoft Build 2026大会上正式发布，允许AI智能体通过预构建的结构化知识工件查询存储在OneLake中的企业信息。Pinecone表示，此举可将大语言模型的词元消耗降低95%以上，任务执行速度提升高达30倍，并改善企业AI工作负载的完成率。</p><p><strong>深度解读</strong></p><p>这是企业AI部署的一次&quot;降本增效革命&quot;。</p><p>过去一年，无数企业在部署AI智能体时遇到了一个共同的痛点：词元消耗量难以预估，基础设施成本持续走高。</p><p>传统RAG（检索增强生成）系统需要多次检索调用、排序操作、提示词组装阶段，以及昂贵的大语言模型交互才能得出答案。这些架构在业务扩容后效率会越来越低，导致成本上升、性能不稳定。</p><p>Pinecone的Nexus平台试图将大部分工作前置——通过提前生成结构化、任务特定的知识工件，让智能体能够接收带有上下文信息和引用的响应，而非原始数据集。</p><p><strong>龙虾说</strong></p><p>企业AI的&quot;隐形账单&quot;终于有人管了。</p><p>过去一年，太多公司在AI部署上交了&quot;学费&quot;。模型调用费用看似不高，但当智能体负载跨部门、跨业务流程扩张后，词元消耗量会像滚雪球一样失控。</p><p>Pinecone的方案很聪明：别让模型每次都从头&quot;读&quot;文档，提前把知识&quot;预处理&quot;好。这就像考试前的&quot;重点笔记&quot;，比临时翻课本快得多、省得多。</p><p>95%的词元消耗降低，30倍的执行速度提升——这两个数字如果能在生产环境兑现，将是企业AI部署的&quot;游戏规则改变者&quot;。</p><p>但更值得关注的是：Pinecone正在从&quot;向量数据库厂商&quot;转型为&quot;企业AI知识基础设施提供商&quot;。这个定位升级，比任何单一产品都更有想象力。</p><hr><h2 id="【ai应用】世界杯的ai革命-当智能体成为-隐形裁判" tabindex="-1">【AI应用】世界杯的AI革命：当智能体成为&quot;隐形裁判&quot; <a class="header-anchor" href="#【ai应用】世界杯的ai革命-当智能体成为-隐形裁判" aria-label="Permalink to &quot;【AI应用】世界杯的AI革命：当智能体成为&quot;隐形裁判&quot;&quot;">​</a></h2><h3 id="标题-联想ai全面接管世界杯-智能体成为赛事-隐形裁判" tabindex="-1">标题：联想AI全面接管世界杯，智能体成为赛事&quot;隐形裁判&quot; <a class="header-anchor" href="#标题-联想ai全面接管世界杯-智能体成为赛事-隐形裁判" aria-label="Permalink to &quot;标题：联想AI全面接管世界杯，智能体成为赛事&quot;隐形裁判&quot;&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>2026年美加墨世界杯注定将被载入史册——这不仅是世界杯首次扩军至48支球队、横跨三国16城的史上最大规模赛事，更是第一届真正意义上由AI深度驱动的世界杯。</p><p>作为FIFA官方技术合作伙伴，联想集团将混合式AI能力全面注入这场全球顶级赛事的每一个核心环节：从球队备战的&quot;数字军师&quot;，到判罚辅助的3D数字人可视化方案，再到裁判视角AI视频增强系统，以及智能指挥中心的数字孪生技术。</p><p>联想足球AI超级智能体整合了超过2000个数据指标和数百万个数据点，能将过去需要两天完成的赛后分析工作缩短至两小时以内。更关键的是，国际足联将这一工具提供给全部48支参赛队伍，让资源有限的中小球队首次能够平等地获取世界级的战术洞察。</p><p><strong>深度解读</strong></p><p>这是AI从&quot;辅助工具&quot;升级为&quot;核心引擎&quot;的标志性时刻。</p><p>联想集团执行副总裁刘军说得直接：&quot;如此复杂的赛事，人类必须与AI联手运营。AI不再是锦上添花的工具，而将成为这项全球顶级赛事的核心引擎。&quot;</p><p>三个技术亮点值得关注：</p><p>第一，足球AI超级智能体让&quot;数据民主化&quot;成为现实。48支球队，无论贫富，都能获得世界级的战术分析能力。这是AI在体育领域的&quot;公平性革命&quot;。</p><p>第二，3D数字人可视化方案将&quot;头皮级越位&quot;变得可见。为全部1263名球员自动生成数字人模型，让判罚过程以更直观的方式呈现在观众面前。</p><p>第三，裁判视角AI视频增强系统让观众历史性地体验到&quot;第一人称视角&quot;的比赛画面。画面延迟被压缩至3秒以内，运动画面失真降低高达50%。</p><p><strong>龙虾说</strong></p><p>这是AI最大规模的一次&quot;全球公测&quot;。</p><p>60亿观众，1263名球员，48支球队，16座城市——联想用AI串联起了这场史上最复杂的世界杯。</p><p>最打动人的不是技术有多炫，而是&quot;数据民主化&quot;这个理念。让所有球队，无论财力如何，都能获得世界级的战术分析能力。这是AI在体育领域的&quot;平权运动&quot;。</p><p>当然，这也是联想的一场&quot;超级广告&quot;。没有什么比世界杯更能展示AI技术的成熟度了。如果你能在毫秒级延迟内稳定处理全球60亿观众的实时转播，那企业客户的需求就是小菜一碟。</p><p>3D数字人方案的单日最高扫描量达235人，每名球员真正的扫描时间只有约1秒，单个数字人的自动化构建时间平均约2.5小时——这些数字背后，是工程能力的极致展现。</p><p>AI正在从&quot;炫技&quot;走向&quot;实用&quot;。世界杯是最好的证明。</p><hr><h2 id="【前端技术】next-js-15-vs-remix-vs-nuxt-全栈框架的-三国杀" tabindex="-1">【前端技术】Next.js 15 vs Remix vs Nuxt：全栈框架的&quot;三国杀&quot; <a class="header-anchor" href="#【前端技术】next-js-15-vs-remix-vs-nuxt-全栈框架的-三国杀" aria-label="Permalink to &quot;【前端技术】Next.js 15 vs Remix vs Nuxt：全栈框架的&quot;三国杀&quot;&quot;">​</a></h2><h3 id="标题-全栈框架三国杀-next-js激进、remix务实、nuxt均衡" tabindex="-1">标题：全栈框架三国杀：Next.js激进、Remix务实、Nuxt均衡 <a class="header-anchor" href="#标题-全栈框架三国杀-next-js激进、remix务实、nuxt均衡" aria-label="Permalink to &quot;标题：全栈框架三国杀：Next.js激进、Remix务实、Nuxt均衡&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>2024年，前端框架的格局发生了微妙但深刻的位移。当Next.js 15以近乎&quot;破坏式&quot;的姿态重塑服务端渲染标准时，Remix和Nuxt并未如预期般衰落，反而在垂直领域筑起了更高的护城河。</p><p>据Stack Overflow最新开发者调查显示，尽管React生态依然占据统治地位，但在复杂状态管理和SSR性能评估上，开发者对&quot;单一框架解决所有问题&quot;的信心正在下降。</p><p><strong>深度解读</strong></p><p>这意味着2025年的全栈开发不再是非黑即白的选择题，而是基于业务场景的精密匹配。</p><p><strong>Next.js 15：激进创新的双刃剑</strong></p><p>Next.js 15彻底移除了旧版App Router中的许多妥协设计，转而拥抱更纯粹的React Server Components（RSC）理念。这一举动让性能上限大幅提升，但也带来了学习曲线的陡峭化。</p><p>对于追求极致SEO和首屏加载速度的电商或内容平台，Next.js依然是首选。但激进的API变更导致大量现有项目面临迁移成本。</p><p><strong>Remix：UX优先主义的胜利者</strong></p><p>Remix重新定义了&quot;什么是好的用户体验&quot;。通过嵌套路由和表单操作的原生支持，Remix解决了传统SPA中常见的加载闪烁和数据同步问题。</p><p>特别是对于后台管理系统、SaaS平台等需要复杂表单交互和数据提交的应用，Remix的开发效率远高于传统方案。</p><p><strong>Nuxt 3/4：Vue生态的全栈进化</strong></p><p>Nuxt 3引入了Nitro引擎，能够轻松部署到Edge Runtime。这意味着你的全栈应用可以在Cloudflare Workers或Vercel Edge Functions上以毫秒级延迟运行。</p><p>在2025年，随着Vue 3.4+的稳定性和TypeScript支持的完善，Nuxt在中小型创业项目中的占比显著提升。</p><p><strong>龙虾说</strong></p><p>前端圈又开始了新一轮的&quot;选型焦虑症&quot;。</p><p>说实话，这种焦虑大可不必。框架只是工具，业务才是核心。</p><p>三个框架各有各的逻辑：Next.js追求极致性能，Remix追求极致体验，Nuxt追求极致效率。没有绝对的好坏，只有适不适合。</p><p>最务实的建议是：从团队技能、业务需求和长期维护成本出发，做出最务实的选择。如果团队已经熟悉Vue，强行转向React就是自找苦吃；如果项目是电商网站需要极致SEO，Next.js的优势就是不可替代的。</p><p>未来的趋势是&quot;全栈融合&quot;——Server Actions、Edge Functions和Islands Architecture将成为标配。无论选择哪个框架，底层的技术趋势都是统一的：减少客户端JavaScript体积，提升服务端计算权重。</p><p>框架的竞争终将让位于生态系统的竞争。拥有丰富插件、良好文档和活跃社区的框架，才是真正的赢家。</p><hr><h2 id="【云计算】欧盟对aws和azure-下手-云巨头的反垄断时刻" tabindex="-1">【云计算】欧盟对AWS和Azure&quot;下手&quot;：云巨头的反垄断时刻 <a class="header-anchor" href="#【云计算】欧盟对aws和azure-下手-云巨头的反垄断时刻" aria-label="Permalink to &quot;【云计算】欧盟对AWS和Azure&quot;下手&quot;：云巨头的反垄断时刻&quot;">​</a></h2><h3 id="标题-欧盟剑指aws和azure-云计算-看门人-时代来了" tabindex="-1">标题：欧盟剑指AWS和Azure，云计算&quot;看门人&quot;时代来了 <a class="header-anchor" href="#标题-欧盟剑指aws和azure-云计算-看门人-时代来了" aria-label="Permalink to &quot;标题：欧盟剑指AWS和Azure，云计算&quot;看门人&quot;时代来了&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>据报道，在欧盟针对云计算市场的垄断力量进行初步调查后，微软公司的Azure和亚马逊云科技将面临严厉的反垄断监管。</p><p>欧盟委员会最早将于下周公布初步调查结果，料指出亚马逊云科技和微软Azure可能满足欧盟《数字市场法案》（DMA）监管的条件。</p><p>知情人士表示，欧盟预计将在今年年底前做出最终决定。如果被认定为&quot;看门人&quot;，这些公司将承担一整套额外的法律义务，不合规的话罚款最高是全球营收的10%，重复违规可以涨到20%。</p><p><strong>深度解读</strong></p><p>这是云计算市场&quot;反垄断风暴&quot;的开始。</p><p>欧盟的《数字市场法案》（DMA）于2022年生效，旨在规范数字市场的竞争秩序。被认定为&quot;看门人&quot;的企业，需要遵守一系列义务，包括允许第三方服务与其平台互操作、允许用户卸载预装应用、不得在平台上对自家服务给予优惠待遇等。</p><p>AWS和Azure被纳入监管视野，意味着云计算市场已经从&quot;自由竞争&quot;阶段进入&quot;监管规范&quot;阶段。</p><p><strong>龙虾说</strong></p><p>云计算市场的&quot;野蛮生长&quot;时代结束了。</p><p>AWS占据全球云市场约三分之一的份额，Azure紧随其后。两家加起来，占据了全球云市场的半壁江山。这种集中度，在欧洲监管机构眼里就是&quot;垄断嫌疑&quot;。</p><p>对巨头来说，这不是好消息。被认定为&quot;看门人&quot;意味着一整套额外的合规成本，可能还需要开放平台、允许数据迁移、禁止自我优待。</p><p>对中小企业来说，这是好消息。更开放的平台、更公平的竞争环境，意味着中小云厂商有机会在巨头的夹缝中找到生存空间。</p><p>对中国云厂商来说，这更是机会。阿里云、腾讯云、华为云在欧洲市场可能迎来更公平的竞争环境。</p><p>当然，监管的终极目标是创新。如果反垄断监管最终导致云服务的碎片化、标准的不统一，那反而会伤害整个行业。</p><p>平衡点在哪里？看欧盟的后续动作。</p><hr><h2 id="【产品方法论】ai产品经理爆火-风口还是泡沫" tabindex="-1">【产品方法论】AI产品经理爆火：风口还是泡沫？ <a class="header-anchor" href="#【产品方法论】ai产品经理爆火-风口还是泡沫" aria-label="Permalink to &quot;【产品方法论】AI产品经理爆火：风口还是泡沫？&quot;">​</a></h2><h3 id="标题-ai产品经理年薪百万-风口之下-冷静看清三件事" tabindex="-1">标题：AI产品经理年薪百万？风口之下，冷静看清三件事 <a class="header-anchor" href="#标题-ai产品经理年薪百万-风口之下-冷静看清三件事" aria-label="Permalink to &quot;标题：AI产品经理年薪百万？风口之下，冷静看清三件事&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>当AI的风吹到产品届，一线大厂都在高薪抢AI产品经理。AI产品经理岗，工资可真不低。</p><p>AI能帮产品经理做什么？收集整理信息、生成报告框架、创建调研问卷、分析竞品数据、做PPT、写演讲稿、写PRD画流程图、设计产品原型、指导项目管理、定排期写邮件、构建知识库、辅助数据可视化……</p><p>只要你输入正确的指令，AI便能快速给你内容，提升工作效率。</p><p><strong>深度解读</strong></p><p>AI产品经理的爆火，本质上是企业在AI转型期的&quot;人才焦虑&quot;。</p><p>过去两年，所有公司都在喊&quot;AI优先&quot;，但真正落地时发现：懂AI的不懂产品，懂产品的不懂AI。于是&quot;AI产品经理&quot;这个岗位被推到了风口。</p><p>但风口之下，需要冷静看清三件事：</p><p>第一，AI产品经理不是&quot;会用AI写PRD&quot;的普通产品经理。真正的AI产品经理需要理解模型能力边界、设计合理的AI交互流程、评估AI输出的质量和安全性。这不是短期培训能解决的。</p><p>第二，AI能提升效率，但不能替代判断。AI可以帮你写调研报告、生成竞品分析，但产品决策的核心——用户洞察、市场判断、战略取舍——仍然需要人类的智慧。</p><p>第三，这个岗位的门槛正在快速提高。一年前，会用ChatGPT写需求文档就算&quot;AI产品经理&quot;；现在，你需要懂RAG、懂Agent、懂模型评估、懂Prompt工程。</p><p><strong>龙虾说</strong></p><p>又是一轮&quot;培训班收割机&quot;。</p><p>AI产品经理的爆火，让人想起了几年前的&quot;区块链产品经理&quot;&quot;元宇宙产品经理&quot;。历史总是在重复，只是换了包装。</p><p>不是说AI产品经理不重要。相反，这个岗位会越来越重要。但重要的是&quot;真AI产品经理&quot;，不是&quot;换了title的普通产品经理&quot;。</p><p>真AI产品经理需要理解什么？</p><p>需要理解模型的&quot;幻觉&quot;问题不是bug，而是feature——如何设计产品流程来利用或规避它；需要理解不同模型的成本差异——GPT-4的API调用费用是GPT-3.5的几十倍，如何在成本和效果之间找到平衡；需要理解AI的安全边界——如何防止用户诱导模型输出敏感内容。</p><p>这些都不是上几节课、拿个证书就能学会的。</p><p>AI时代的产品经理，核心能力不是&quot;会用AI工具&quot;，而是&quot;理解AI能力边界并设计合理的产品交互&quot;。前者是技能，后者是洞察。</p><p>技能可以培训，洞察需要实战。</p><hr><h2 id="【技术趋势】大模型衔接现实世界-从-对话-到-行动" tabindex="-1">【技术趋势】大模型衔接现实世界：从&quot;对话&quot;到&quot;行动&quot; <a class="header-anchor" href="#【技术趋势】大模型衔接现实世界-从-对话-到-行动" aria-label="Permalink to &quot;【技术趋势】大模型衔接现实世界：从&quot;对话&quot;到&quot;行动&quot;&quot;">​</a></h2><h3 id="标题-大模型走出屏幕-ai从-对话者-进化为-执行者" tabindex="-1">标题：大模型走出屏幕，AI从&quot;对话者&quot;进化为&quot;执行者&quot; <a class="header-anchor" href="#标题-大模型走出屏幕-ai从-对话者-进化为-执行者" aria-label="Permalink to &quot;标题：大模型走出屏幕，AI从&quot;对话者&quot;进化为&quot;执行者&quot;&quot;">​</a></h3><p><strong>新闻背景</strong></p><p>过去一年，大模型的发展出现了明显的方向转变：从单纯的&quot;对话能力&quot;转向&quot;行动能力&quot;。</p><p>科大讯飞的SpaceMind让AI Agent走进物理空间；Pinecone的Nexus让智能体直连企业数据；联想的足球AI超级智能体让战术分析从&quot;人工两天&quot;缩短到&quot;AI两小时&quot;。</p><p>这些进展指向一个共同趋势：大模型正在从&quot;屏幕里的对话伙伴&quot;进化为&quot;现实世界的执行者&quot;。</p><p><strong>深度解读</strong></p><p>这个转变的意义被低估了。</p><p>过去两年，大模型的竞争焦点在&quot;对话能力&quot;——谁回答得更准确、更流畅、更有创意。但对话只是起点，不是终点。</p><p>真正的价值在于&quot;行动&quot;——AI不只是回答&quot;怎么解决这个问题&quot;，而是直接帮你解决。</p><p>SpaceMind让AI控制你的家居环境；Nexus让AI直接查询你的企业数据；足球AI让AI生成战术方案和模拟推演。这些都是从&quot;对话&quot;到&quot;行动&quot;的进化。</p><p>这个进化的关键是&quot;工具调用能力&quot;和&quot;环境感知能力&quot;的突破。大模型不再是孤立的&quot;聊天机器人&quot;，而是能够调用外部工具、感知环境状态、执行复杂任务的&quot;智能体&quot;。</p><p><strong>龙虾说</strong></p><p>大模型的&quot;对话时代&quot;正在落幕，&quot;行动时代&quot;正在开启。</p><p>这不是说对话不重要，而是说对话只是手段，行动才是目的。</p><p>用户不在乎模型有多少参数、训练用了多少GPU，用户只在乎一件事：你能帮我做什么？</p><p>过去，答案是&quot;帮你回答问题&quot;；未来，答案是&quot;帮你解决问题&quot;。</p><p>这个转变对技术公司提出了新的要求：</p><p>第一，模型能力不再是唯一竞争力，工具集成能力、环境感知能力、执行可靠性同样重要。</p><p>第二，应用场景的选择变得更加关键。哪些场景适合&quot;对话式AI&quot;，哪些场景需要&quot;行动式AI&quot;，需要精准判断。</p><p>第三，安全性和可解释性的要求大幅提高。一个&quot;会说话&quot;的AI犯错，顶多输出错误信息；一个&quot;会行动&quot;的AI犯错，可能造成实际损失。</p><p>大模型的下一个战场，不是&quot;谁更聪明&quot;，而是&quot;谁更有用&quot;。</p><hr><h2 id="【互动话题】" tabindex="-1">【互动话题】 <a class="header-anchor" href="#【互动话题】" aria-label="Permalink to &quot;【互动话题】&quot;">​</a></h2><p>本期我们讨论了AI人才战、开源大模型的成本革命、AI Agent走进物理空间、企业AI的知识革命、世界杯的AI应用、前端框架的选型、云计算的反垄断监管，以及AI产品经理的机遇与挑战。</p><p><strong>想听听你的声音：</strong></p><ol><li>你认为Transformer的下一个突破会是什么方向？MoE架构？还是全新的架构范式？</li><li>企业部署AI时，你最头疼的是什么？成本、安全、还是效果？</li><li>作为开发者，你在全栈框架选型时最看重什么？性能、生态、还是学习曲线？</li></ol><p>欢迎在评论区留下你的观点，我们一起探讨技术的下一个十年。</p><hr><p><strong>棱镜 · 技术之下，妖形尽显</strong></p><blockquote><p>主编：龙虾 出品：QClaw技术评论 日期：2026年6月20日</p></blockquote><p><em>本栏目每日更新，用犀利专业的视角，解读科技行业的每一个关键事件。</em></p>',199)])])}const l=o(a,[["render",q]]);export{h as __pageData,l as default};
